// CF08 WF_DAILY_IDEAS — normalize triggers, scope the project list.
// Triggers:
//   - Schedule (daily 07:00 UTC): no payload, scope = all active projects
//   - Webhook POST /webhook/ideas/generate: optional { project_id, force }
// Output: one item per project to process.
// Global fetch + $env per MEMORY.md (n8n 2.8.4 task runner compat).

const raw = $input.first().json;
const viaWebhook = !!raw.body;
const payload = raw.body || {};
const projectIdFilter = payload.project_id || null;
const force = payload.force === true;

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

// Compute today's UTC date (YYYY-MM-DD) for run_date + idempotency
const now = new Date();
const runDate = now.toISOString().slice(0, 10);

// Scope projects. Webhook with project_id = single project; cron/manual-all = all non-paused/archived.
let projUrl;
if (projectIdFilter) {
  projUrl = `${supabaseUrl}/rest/v1/projects?id=eq.${projectIdFilter}&select=id,name,niche,niche_description,niche_rpm_category,estimated_rpm_low,estimated_rpm_mid,estimated_rpm_high,niche_health_score,status`;
} else {
  // 'active' is the canonical production status; also allow null (legacy rows) but skip paused/archived
  projUrl = `${supabaseUrl}/rest/v1/projects?status=not.in.(paused,archived)&select=id,name,niche,niche_description,niche_rpm_category,estimated_rpm_low,estimated_rpm_mid,estimated_rpm_high,niche_health_score,status`;
}

const projRes = await fetch(projUrl, { method: 'GET', headers: sbHeaders });
if (!projRes.ok) {
  throw new Error(`Fetch projects failed: HTTP ${projRes.status}: ${await projRes.text()}`);
}
const projects = await projRes.json();

if (!Array.isArray(projects) || projects.length === 0) {
  return [{
    json: {
      skipped: true,
      reason: projectIdFilter
        ? `Project ${projectIdFilter} not found`
        : 'No active projects found',
      via_webhook: viaWebhook,
      run_date: runDate
    }
  }];
}

return projects.map(p => ({
  json: {
    project_id: p.id,
    project: p,
    force,
    via_webhook: viaWebhook,
    run_date: runDate,
    triggered_at: now.toISOString()
  }
}));

// CF08 per-project idea generator.
// For one project: idempotency check -> load context (topics, keywords, outliers,
// synthesis) -> call Claude Opus 4.6 with embedded prompt -> validate & clamp ->
// bulk INSERT 15-20 daily_ideas rows -> log to production_logs.
// Single retry to top up if Claude returns <15 ideas.

const data = $input.item.json;
if (data.skipped) return $input.item;

const projectId = data.project_id;
const project = data.project || {};
const force = data.force === true;
const runDate = data.run_date;
const runStart = Date.now();

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};
const anthropicKey = $env.ANTHROPIC_API_KEY;

const sleep = (ms) => new Promise(r => setTimeout(r, ms));

async function logProduction(action, status, durationMs, costUsd, retryCount, extraDetails) {
  try {
    await fetch(`${supabaseUrl}/rest/v1/production_logs`, {
      method: 'POST',
      headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify({
        project_id: projectId,
        topic_id: null,
        stage: 'daily_ideas',
        scene_number: null,
        action,
        status,
        duration_ms: durationMs,
        cost_usd: costUsd,
        retry_count: retryCount
      })
    });
  } catch (_) { /* best-effort */ }
}

async function sbGet(url, label) {
  const res = await fetch(url, { method: 'GET', headers: sbHeaders });
  if (!res.ok) throw new Error(`${label} failed: HTTP ${res.status}: ${(await res.text()).slice(0, 200)}`);
  return res.json();
}

// 1. Idempotency — skip if any daily_ideas row already exists for (project_id, run_date)
if (!force) {
  try {
    const dupUrl = `${supabaseUrl}/rest/v1/daily_ideas?project_id=eq.${projectId}&run_date=eq.${runDate}&select=id&limit=1`;
    const dupRes = await fetch(dupUrl, { method: 'GET', headers: sbHeaders });
    if (dupRes.ok) {
      const dupArr = await dupRes.json();
      if (Array.isArray(dupArr) && dupArr.length > 0) {
        await logProduction('idempotent_skip', 'skipped', Date.now() - runStart, 0, 0);
        return {
          json: {
            project_id: projectId,
            skipped: true,
            reason: `Ideas already generated for ${runDate} (pass force=true to regenerate)`,
            run_date: runDate,
            via_webhook: data.via_webhook
          }
        };
      }
    }
  } catch (_) { /* non-fatal — proceed */ }
}

// 2. Load context (parallel where safe)
const recentTopicsUrl = `${supabaseUrl}/rest/v1/topics?project_id=eq.${projectId}&status=eq.published&select=seo_title,selected_title,original_title&order=published_at.desc.nullslast&limit=20`;
const keywordsUrl = `${supabaseUrl}/rest/v1/keywords?project_id=eq.${projectId}&select=keyword,opportunity_score&order=opportunity_score.desc.nullslast&limit=10`;
const sevenDaysAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString();
const outliersUrl = `${supabaseUrl}/rest/v1/competitor_videos?project_id=eq.${projectId}&is_outlier=eq.true&published_at=gte.${sevenDaysAgo}&select=title,channel_name:competitor_channel_id,views_7d,outlier_ratio&order=outlier_ratio.desc&limit=10`;
const synthesisUrl = `${supabaseUrl}/rest/v1/competitor_intelligence?project_id=eq.${projectId}&select=weekly_synthesis&order=created_at.desc&limit=1`;

let recentTopics = [];
let keywords = [];
let outlierVideos = [];
let weeklySynthesis = '';

try { recentTopics = await sbGet(recentTopicsUrl, 'fetch topics'); } catch (_) {}
try { keywords = await sbGet(keywordsUrl, 'fetch keywords'); } catch (_) {}
try { outlierVideos = await sbGet(outliersUrl, 'fetch outliers'); } catch (_) {}
try {
  const synthArr = await sbGet(synthesisUrl, 'fetch synthesis');
  weeklySynthesis = (synthArr && synthArr[0] && synthArr[0].weekly_synthesis) ? String(synthArr[0].weekly_synthesis).slice(0, 2000) : '';
} catch (_) {}

// Resolve competitor channel names for outlier list (best-effort join)
if (Array.isArray(outlierVideos) && outlierVideos.length > 0) {
  const channelIds = Array.from(new Set(outlierVideos.map(v => v.channel_name).filter(Boolean)));
  if (channelIds.length > 0) {
    try {
      const csv = channelIds.map(c => `"${c}"`).join(',');
      const chArr = await sbGet(`${supabaseUrl}/rest/v1/competitor_channels?id=in.(${csv})&select=id,channel_name`, 'fetch channel names');
      const nameMap = new Map((chArr || []).map(c => [c.id, c.channel_name]));
      outlierVideos = outlierVideos.map(v => ({ ...v, channel_name: nameMap.get(v.channel_name) || 'competitor' }));
    } catch (_) {
      outlierVideos = outlierVideos.map(v => ({ ...v, channel_name: 'competitor' }));
    }
  }
}

// 3. Build the embedded prompt
const name = project.name || '(unnamed project)';
const niche = project.niche || '';
const nicheDesc = project.niche_description || '';
const rpmCat = project.niche_rpm_category || 'uncategorized';
const rpmMid = project.estimated_rpm_mid != null ? Number(project.estimated_rpm_mid) : 0;

const recentTopicsBlock = (recentTopics || []).map(t => `- ${t.selected_title || t.seo_title || t.original_title || '(untitled)'}`).join('\n') || '(none yet)';
const keywordsBlock = (keywords || []).map(k => `- ${k.keyword} (opportunity ${k.opportunity_score != null ? k.opportunity_score : 'n/a'})`).join('\n') || '(none loaded)';
const outliersBlock = (outlierVideos || []).map(v => `- "${v.title}" (${v.channel_name}, ${Number(v.views_7d || 0).toLocaleString()} views, ${Number(v.outlier_ratio || 0).toFixed(1)}x)`).join('\n') || '(no breakouts detected)';
const synthesisBlock = weeklySynthesis ? `Latest competitor synthesis:\n${weeklySynthesis}` : '';

function buildPrompt(extraCount) {
  const extraInstruction = extraCount ? `\n\n[FOLLOW-UP] Previous response returned fewer than 15 ideas. Generate ${extraCount} ADDITIONAL fresh ideas that do NOT overlap with anything already implied by the context above.` : '';
  return `You are a YouTube content strategist. Generate 20 fresh video ideas for this channel.

Project: ${name}
Niche: ${niche} (${nicheDesc})
RPM category: ${rpmCat} (estimated $${rpmMid}/1K views)

Recent published topics (avoid duplicating these angles):
${recentTopicsBlock}

Top-opportunity keywords (prefer incorporating):
${keywordsBlock}

Competitor outlier breakouts in last 7 days:
${outliersBlock}

${synthesisBlock}

RULES:
- Produce EXACTLY 20 ideas, ranked best-to-worst by combined_score.
- No duplicates of recent topics or obvious rephrasings.
- Mix evergreen hooks with timely topical angles (roughly 70/30).
- Each idea must be a compelling YouTube title, not a generic topic.
- For each, score 3 dimensions:
  * viral_potential_score (0-100): how much algorithmic push energy does this topic have RIGHT NOW?
  * seo_opportunity_score (0-100): search demand + competition inverse combined
  * rpm_fit_score (0-100): does this topic fit the niche's premium-advertiser category?
- combined_score = round(viral * 0.45 + seo * 0.35 + rpm_fit * 0.20)
- For each idea, include a 2-3 sentence rationale that REFERENCES specific context signals.
- target_chapters: optional 3-5 chapter breakdown if the idea is deep enough.
- related_keywords: 3-5 keywords this idea naturally targets.${extraInstruction}

Return ONLY valid JSON (no markdown):
{
  "ideas": [
    {
      "idea_title": "<string, 55-70 chars>",
      "idea_angle": "<1 sentence hook>",
      "target_chapters": ["<chapter 1>", "<chapter 2>"],
      "viral_potential_score": <int>,
      "seo_opportunity_score": <int>,
      "rpm_fit_score": <int>,
      "combined_score": <int>,
      "rationale": "<2-3 sentences tying to specific context signals>",
      "related_keywords": ["<kw>", "<kw>"],
      "source_signals": {"competitor_titles": ["<title>"], "trending_keywords": ["<kw>"], "recent_topics": []}
    }
  ]
}`;
}

// 4. Claude Opus 4.6 call with inline backoff (1s -> 2s -> 4s -> 8s, max 4, 30s cap)
async function callClaude(promptText, maxRetries = 4) {
  let lastErr = null;
  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      const res = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: {
          'x-api-key': anthropicKey,
          'anthropic-version': '2023-06-01',
          'content-type': 'application/json'
        },
        body: JSON.stringify({
          model: 'claude-opus-4-6',
          max_tokens: 4000,
          messages: [{ role: 'user', content: promptText }]
        })
      });
      if (res.ok) {
        const body = await res.json();
        return {
          ok: true,
          text: body.content?.[0]?.text || '',
          input_tokens: body.usage?.input_tokens || 0,
          output_tokens: body.usage?.output_tokens || 0,
          attempts: attempt
        };
      }
      const errBody = await res.text();
      if (res.status === 429) await sleep(30000);
      lastErr = new Error(`HTTP ${res.status}: ${errBody.slice(0, 300)}`);
      if (res.status >= 400 && res.status < 500 && res.status !== 429) break;
    } catch (e) { lastErr = e; }
    if (attempt < maxRetries) await sleep(Math.min(1000 * Math.pow(2, attempt - 1), 30000));
  }
  return { ok: false, error: lastErr?.message || 'opus_daily_ideas failed', attempts: maxRetries };
}

function parseIdeasJson(text) {
  if (!text) return null;
  const clean = text.replace(/```json|```/g, '').trim();
  try { const parsed = JSON.parse(clean); return parsed && Array.isArray(parsed.ideas) ? parsed.ideas : null; } catch {}
  const m = clean.match(/\{[\s\S]*\}/);
  if (m) { try { const parsed = JSON.parse(m[0]); return parsed && Array.isArray(parsed.ideas) ? parsed.ideas : null; } catch {} }
  return null;
}

function clampScore(n) { const v = Number(n); if (!Number.isFinite(v)) return 50; return Math.max(0, Math.min(100, Math.round(v))); }
function sanitizeString(s, maxLen) { return String(s == null ? '' : s).slice(0, maxLen); }
function sanitizeArray(arr, maxItems, maxStrLen) {
  if (!Array.isArray(arr)) return [];
  return arr.slice(0, maxItems).map(x => sanitizeString(x, maxStrLen)).filter(x => x.length > 0);
}

const claudeStart = Date.now();
const firstRes = await callClaude(buildPrompt(0), 4);
let rawIdeas = firstRes.ok ? parseIdeasJson(firstRes.text) : null;
let totalInputTokens = firstRes.input_tokens || 0;
let totalOutputTokens = firstRes.output_tokens || 0;
let totalAttempts = firstRes.attempts || 0;
let firstError = firstRes.ok ? null : firstRes.error;

// Single top-up retry if under 15
if (rawIdeas && rawIdeas.length > 0 && rawIdeas.length < 8) {
  const need = 20 - rawIdeas.length;
  const topUpRes = await callClaude(buildPrompt(need), 4);
  if (topUpRes.ok) {
    const extra = parseIdeasJson(topUpRes.text) || [];
    rawIdeas = rawIdeas.concat(extra);
    totalInputTokens += topUpRes.input_tokens || 0;
    totalOutputTokens += topUpRes.output_tokens || 0;
    totalAttempts += topUpRes.attempts || 0;
  }
}

const claudeDuration = Date.now() - claudeStart;

// 5. Validate — require 15-20 ideas. If <15, bail without inserting.
if (!rawIdeas || rawIdeas.length < 8) {
  await logProduction('opus_insufficient_ideas', 'error', claudeDuration, 0, totalAttempts, null);
  return {
    json: {
      success: false,
      project_id: projectId,
      error: rawIdeas ? `Only ${rawIdeas.length} ideas returned (need 15+)` : (firstError || 'Claude returned no valid ideas'),
      ideas_inserted: 0,
      claude_ok: firstRes.ok,
      run_date: runDate,
      via_webhook: data.via_webhook
    }
  };
}

// Clamp to 20 max
if (rawIdeas.length > 20) rawIdeas = rawIdeas.slice(0, 20);

// 6. Generate batch_id (UUID v4) locally — same for all rows in this run
function uuidv4() {
  // RFC 4122 v4 — hex chars, no crypto dependency
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (c) => {
    const r = (Math.random() * 16) | 0;
    const v = c === 'x' ? r : (r & 0x3) | 0x8;
    return v.toString(16);
  });
}
const batchId = uuidv4();

// 7. Build insert payload with authoritative combined_score recomputation
const nowIso = new Date().toISOString();
const rows = rawIdeas.map((idea, idx) => {
  const viral = clampScore(idea.viral_potential_score);
  const seo = clampScore(idea.seo_opportunity_score);
  const rpmFit = clampScore(idea.rpm_fit_score);
  const combined = Math.round(viral * 0.45 + seo * 0.35 + rpmFit * 0.20);

  // target_chapters: JSONB array of strings
  let targetChapters = null;
  if (Array.isArray(idea.target_chapters)) {
    const arr = sanitizeArray(idea.target_chapters, 5, 200);
    targetChapters = arr.length > 0 ? arr : null;
  }

  // source_signals: JSONB
  let sourceSignals = null;
  if (idea.source_signals && typeof idea.source_signals === 'object') {
    sourceSignals = {
      competitor_titles: sanitizeArray(idea.source_signals.competitor_titles, 5, 300),
      trending_keywords: sanitizeArray(idea.source_signals.trending_keywords, 5, 100),
      recent_topics: sanitizeArray(idea.source_signals.recent_topics, 5, 300)
    };
  }

  // related_keywords: JSONB array
  const relatedKeywords = sanitizeArray(idea.related_keywords, 5, 100);

  return {
    project_id: projectId,
    run_date: runDate,
    batch_id: batchId,
    position_in_batch: idx + 1,
    idea_title: sanitizeString(idea.idea_title, 300) || `Idea ${idx + 1}`,
    idea_angle: sanitizeString(idea.idea_angle, 1000),
    target_chapters: targetChapters,
    viral_potential_score: viral,
    seo_opportunity_score: seo,
    rpm_fit_score: rpmFit,
    combined_score: combined,
    rationale: sanitizeString(idea.rationale, 2000),
    source_signals: sourceSignals,
    related_keywords: relatedKeywords.length > 0 ? relatedKeywords : null,
    status: 'pending',
    status_changed_at: nowIso
  };
});

// Re-sort by combined_score DESC and renumber position_in_batch (authoritative)
rows.sort((a, b) => b.combined_score - a.combined_score);
rows.forEach((r, i) => { r.position_in_batch = i + 1; });

// 8. Bulk INSERT — single array body with return=minimal.
// Fallback: if bulk fails, try one-by-one to salvage what we can.
let ideasInserted = 0;
let insertError = null;
try {
  const bulkRes = await fetch(`${supabaseUrl}/rest/v1/daily_ideas`, {
    method: 'POST',
    headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify(rows)
  });
  if (bulkRes.ok) {
    ideasInserted = rows.length;
  } else {
    insertError = `bulk insert HTTP ${bulkRes.status}: ${(await bulkRes.text()).slice(0, 200)}`;
  }
} catch (e) {
  insertError = e.message;
}

if (ideasInserted === 0 && insertError) {
  // Fallback: insert one row at a time
  for (const row of rows) {
    try {
      const oneRes = await fetch(`${supabaseUrl}/rest/v1/daily_ideas`, {
        method: 'POST',
        headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
        body: JSON.stringify(row)
      });
      if (oneRes.ok) ideasInserted += 1;
    } catch (_) { /* continue */ }
  }
}

// 9. Cost estimate — Opus 4.6 pricing: $15/M input, $75/M output
const claudeCostUsd = ((totalInputTokens * 15) + (totalOutputTokens * 75)) / 1_000_000;
const costRounded = Math.round(claudeCostUsd * 10000) / 10000;

const finalStatus = (ideasInserted >= 15) ? 'success' : (ideasInserted > 0 ? 'partial' : 'error');
await logProduction('opus_generate_ideas', finalStatus, Date.now() - runStart, costRounded, totalAttempts, null);

return {
  json: {
    success: ideasInserted >= 15,
    project_id: projectId,
    batch_id: batchId,
    run_date: runDate,
    ideas_generated: rows.length,
    ideas_inserted: ideasInserted,
    insert_error: insertError,
    claude_ok: firstRes.ok,
    claude_cost_usd: costRounded,
    claude_input_tokens: totalInputTokens,
    claude_output_tokens: totalOutputTokens,
    duration_ms: Date.now() - runStart,
    via_webhook: data.via_webhook
  }
};

// Summarize all per-project results into a single response payload.
const items = $input.all().map(i => i.json || {});

// If the first item is a top-level skipped/error envelope (no per-project iteration), pass through.
if (items.length === 1 && items[0].skipped && !items[0].project_id) {
  return [{ json: { ...items[0], http_status: 200 } }];
}

const projectsTotal = items.length;
const projectsGenerated = items.filter(r => r.success === true).length;
const projectsSkipped = items.filter(r => r.skipped === true).length;
const projectsFailed = items.filter(r => r.success === false && !r.skipped).length;
const totalIdeasInserted = items.reduce((a, r) => a + (Number(r.ideas_inserted) || 0), 0);
const totalCostUsd = items.reduce((a, r) => a + (Number(r.claude_cost_usd) || 0), 0);

const viaWebhook = items.some(r => r.via_webhook === true);
const runDate = items.find(r => r.run_date)?.run_date || new Date().toISOString().slice(0, 10);

return [{
  json: {
    success: projectsGenerated > 0 || projectsSkipped === projectsTotal,
    run_date: runDate,
    projects_total: projectsTotal,
    projects_generated: projectsGenerated,
    projects_skipped: projectsSkipped,
    projects_failed: projectsFailed,
    total_ideas_inserted: totalIdeasInserted,
    total_cost_usd: Math.round(totalCostUsd * 10000) / 10000,
    per_project: items.map(r => ({
      project_id: r.project_id,
      success: r.success === true,
      skipped: r.skipped === true,
      ideas_inserted: r.ideas_inserted || 0,
      error: r.error || r.insert_error || null
    })),
    via_webhook: viaWebhook,
    http_status: 200
  }
}];
